```ts
const handleListTools = (req: Request, url: URL, state: ServerState): Response => {
  const authError = checkBearerAuth(req, state.wsSecret);
  if (authError) return authError;

  const pluginFilter = url.searchParams.get('plugin');
  const allTools = getAllToolsList(state);

  // Annotate each tool with its plugin name for filtering
  const annotated = allTools.map(t => {
    // Browser tools have no underscore prefix pattern
    const browserTool = state.cachedBrowserTools.find(bt => bt.name === t.name);
    if (browserTool) return { ...t, plugin: 'browser' };
    // Platform tools
    if (PLATFORM_TOOL_NAMES.has(t.name)) return { ...t, plugin: 'platform' };
    // Plugin tools: extract plugin name from prefixed name (slack_send_message → slack)
    const lookup = state.registry.toolLookup.get(t.name);
    return { ...t, plugin: lookup?.pluginName ?? 'unknown' };
  });

  const filtered = pluginFilter
    ? annotated.filter(t => t.plugin === pluginFilter)
    : annotated;

  return Response.json(filtered);
};
```

